278	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
279	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
280	    let required = match rbtdrm_required_colophons(fixture) {
281	        Some(r) => r,
282	        None => {
283	            return Err(format!(
284	                "rbtd: unknown fixture '{}' — not registered in manifest",
285	                fixture
286	            ));
287	        }
288	    };
289	    for colophon in required {
290	        let found = manifest.split_whitespace().any(|token| token == *colophon);
291	        if !found {
292	            return Err(format!(
293	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
294	                colophon, fixture
295	            ));
296	        }
297	    }
298	    Ok(())
299	}
