23	/// Single source of truth for the moorings directory name, mirroring bash
24	/// RBCC_moorings_dir across the language boundary. Defined as a macro, not a
25	/// const, so bundled path constants can compose from it at compile time:
26	/// `concat!` rejects a const *identifier* (an opaque name by expansion time)
27	/// but eagerly expands a `macro_rules!` invocation, consuming the literal
28	/// token it produces. Zero dependency, zero runtime cost, no textual
29	/// repetition — every moorings path derives from this one literal.
30	#[macro_export]
31	macro_rules! rbtd_moorings_dir {
32	    () => {
33	        "rbmm_moorings"
34	    };
35	}
36	
37	/// Vessels directory, composed from the moorings dir (single-sources both the
38	/// `rbmm_moorings` root and the `rbmv_vessels` subdir).
39	#[macro_export]
40	macro_rules! rbtd_vessels_dir {
41	    () => {
42	        concat!($crate::rbtd_moorings_dir!(), "/rbmv_vessels")
43	    };
44	}
